interface QuoteItem {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: QuoteItem[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  amulet: 60,
};

export function runScenario(scenario: Scenario): {
  results: { premium: number }[];
} {
  const results = scenario.steps.map((step) => {
    const policyBase = step.items.reduce(
      (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
      0,
    );
    const firstInsurance = policyBase * 0.1;
    const premium = Math.ceil(policyBase + firstInsurance + 5);
    return { premium };
  });
  return { results };
}
